import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    public void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS
        String sanitizedInput = sanitizeInput(userInput);

        // Output safe user input in the response
        PrintWriter out = response.getWriter();
        out.println("<html>");
        out.println("<body>");
        out.println("<h1>Hello, " + sanitizedInput + "</h1>");
        out.println("</body>");
        out.println("</html>");
    }

    private String sanitizeInput(String input) {
        // Implement proper input sanitization logic here
        // For example, you can use OWASP Java Encoder library or a custom sanitizer function
        // Here is an example using OWASP Java Encoder for HTML content:
        return org.owasp.encoder.Encode.forHtmlContent(input);
    }
}

